local LMapBase = LMapBase
---@class LStoryMap:LMapBase
local LStoryMap = LxClass("LStoryMap",LMapBase)

-----------------------------------------------------------------
local typeMapBTIdleController = typeof(CardEHT.MapBTIdleController)

-----------------------------------------------------------------
function LStoryMap:LStoryMap()
    self:InitData()
end

function LStoryMap:OnDestroy()
    local manager = self:GetManager()
    if manager and manager:IsStoryStop() then
        gLGpManager:DestroyGp(LGamePlayType.STORYCOPY)
    end

    LMapBase.OnDestroy(self)
end

function LStoryMap:OnCreate()
    LMapBase.OnCreate(self)
end

function LStoryMap:OnResetMap()
    local manager = self:GetManager()
    if  manager and manager:IsStoryStop() then
        manager:Clear()
    end

    self:InitCurStoryData()
end


function LStoryMap:OnExitMap()

    local manager = self:GetManager()
    if manager then
        manager:OnExitMap()
    end

    self:ResetCameraPara()
end

function LStoryMap:CheckNeedChange()
    return true
end

function LStoryMap:IsCheckClear()
    return true
end

function LStoryMap:ResetCameraPara()

    printInfoN("LStoryMap:ResetCameraPara()")
    if not self._mapCameraCom then
        return
    end
    local camera = self._mapCameraCom.mCamera
    if not camera then
        return
    end

    CS.TimeLinePlayer.DestroyTimeLinePlayer(camera.gameObject)
    camera.orthographicSize = LUtil.GetCameraSize()
end

-----------------------------------------------------------------

function LStoryMap:InitCurStoryData()

    local mapName = self:GetMapArg("mapName")
    if not mapName then
        mapName = gModelPlot:GetPara("storyFristScene")
    end
    self:SetMapName(mapName)
end

function LStoryMap:OnEnterMap()
	self:InitPostProcess()
	
    local isFromStory = self:GetMapArg("isFromStory")
    if not isFromStory then
        return
    end
    local manager = self:GetManager()
    if not manager then
        return
    end

    self:InitUIEvent()

    local type = manager:GetStorySceneType()
    local size = LUtil.GetCameraSize()
    if type == 10 then
        size = 5.18
    end

    local camera = self._mapCameraCom.mCamera
    if not camera then
        return
    end

    camera.orthographicSize = size


    local wellTranMap = {}
    wellTranMap[1] = CS.FindTrans(self._mapTrans,"LayerRoot/Moquan1")
    wellTranMap[2] = CS.FindTrans(self._mapTrans,"LayerRoot/Moquan2")
    wellTranMap[3] = CS.FindTrans(self._mapTrans,"LayerRoot/Moquan3")


    self._wellTranMap = wellTranMap

    self:RefreshWellShow()

    self:TempEventRecv(EventNames.ON_BATTLE_NODE_CHANGE,function ()
        self:RefreshWellShow()
    end)

    manager:OnMapLoaded(self._mapTrans)
end

function LStoryMap:InitPostProcess()
	-- 这里先初始化一下post
	gLGamePostProcess:ShowSceneGray(0.2, 0, function()
		gLGamePostProcess:HideSceneGray(0)
	end)
end

-----------------------------------------------------------------
function LStoryMap:InitCameraComponent()
    local layerRoot = CS.FindTrans(self._mapTrans,"LayerRoot")
    local com = layerRoot:GetComponent(typeMapBTIdleController)
    self._mapCameraCom = com


end

function LStoryMap:UpdateMapVisible()
    if not self:IsMapValid() then
        return
    end

    local bDisableAll = not self._bVisible
    self._mapCameraCom.bDisableAll = bDisableAll
    if bDisableAll then
        self._mapCameraCom:DoDisableAll()
    end
    LMapBase.UpdateMapVisible(self)
end

function LStoryMap:OnCameraAdapt()
end

function LStoryMap:GetManager()
    if gLGpManager and gLGpManager:IsGpInit(LGamePlayType.STORYCOPY) then
        local impl = gLGpManager:FindStoryCopyGp()
        return impl
    end
end

function LStoryMap:InitData()
    self._mapEventCfg =
    {
        {name = "LayerRoot/zhaohuan", func = function() self:OnClickCall() end},
        {name = "LayerRoot/dreamfountain", func = function() self:OnClickDream() end},
    }
end

function LStoryMap:OnClickCall()
    if not self:GetManager():IsEventRunning(10210) then
        return
    end
    local callName = gModelCallHero:GetCallWndName()
    GF.OpenWnd(callName)
end

function LStoryMap:OnClickDream()
    if not self:GetManager():IsEventRunning(10230) then
        return
    end
    --gModelDreamFountain:OnDreamFountainReceiveReq()
end

function LStoryMap:InitUIEvent()
    local len = #self._mapEventCfg
    for i=1,len do
        local buildingInfo = self._mapEventCfg[i]
        local btn = CS.FindTrans(self._mapTrans,buildingInfo.name)
        if btn then
            local func = buildingInfo.func
            if func ~= nil then
                self:SetBuildClick(btn, func)
            end
        end
    end
end

function LStoryMap:RefreshWellShow()
    local battleNode = gModelInstance:GetBattleNode()
    local isStoryNode = gModelPlot:IsStoryInstance(battleNode)
    for k,v in pairs(self._wellTranMap) do
        CS.ShowObject(v,not isStoryNode)
    end
end

-----------------------------------------------------------------

return LStoryMap
